module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const headColor = (args.headcolor && String(args.headcolor).trim()) ? args.headcolor : color;
const showCauses = String(args.showcauses) !== 'false';
const compact = String(args.compact) === 'true';
const hw = Math.max(80, Math.min(400, parseFloat(args.headwidth) || 200));
const secs = sections.map((s) => (s || '').trim()).filter(Boolean);
if (secs.length < 2) return `<div>(fishbone: first section = effect, then category sections)</div>`;
const effect = secs[0];
const cats = secs.slice(1).map((s) => {
  const nl = s.indexOf('\n');
  return {
    name: nl >= 0 ? s.slice(0, nl).trim() : s,
    causes: nl >= 0 ? s.slice(nl + 1).split('\n').map((l) => l.replace(/^-\s+/, '').trim()).filter(Boolean) : [],
  };
});
const top = cats.filter((_, i) => i % 2 === 0);
const bottom = cats.filter((_, i) => i % 2 === 1);
const cols = Math.max(top.length, bottom.length, 1);
const cat = (c, dir) => {
  let causes = '';
  if (showCauses) c.causes.forEach((x) => { causes += `<div class="mdp-fbn-cause">${esc(x)}</div>`; });
  return `<div class="mdp-fbn-cat mdp-fbn-${dir}"><div class="mdp-fbn-catname">${esc(c.name)}</div>` +
    `<div class="mdp-fbn-causes">${causes}</div><div class="mdp-fbn-bone"></div></div>`;
};
let html = `\n\n<div class="mdp-mod-fishbone${compact ? ' mdp-fbn-compact' : ''}" style="--fbn-c:${color}; --fbn-head:${headColor}; --fbn-cols:${cols}; --fbn-hw:${hw}px;">` +
  `<div class="mdp-fbn-grid">` +
  `<div class="mdp-fbn-row mdp-fbn-toprow">${top.map((c) => cat(c, 'top')).join('')}</div>` +
  `<div class="mdp-fbn-spinewrap"><div class="mdp-fbn-spine"></div></div>` +
  `<div class="mdp-fbn-row mdp-fbn-bottomrow">${bottom.map((c) => cat(c, 'bottom')).join('')}</div>` +
  `</div>` +
  `<div class="mdp-fbn-head">\n\n${effect}\n\n</div>` +
  `</div>\n\n`;
return html;
